function initWritingTagFilter(){const o=new URLSearchParams(window.location.search),n=(o.get("tag")||"").trim().toLowerCase();if(!n)return;const e=window.location.pathname,t=e.endsWith("/")?e:`${e}/`,i=/(?:^|\/)writing\/$/.test(t)||/(?:^|\/)sv\/texter\/$/.test(t)||/(?:^|\/)post\/$/.test(t);if(!i)return;const s=document.querySelectorAll(".place-article > .article-card[data-tags]");if(!s.length)return;s.forEach(e=>{const t=e.closest(".place-article");if(!t)return;const s=(e.getAttribute("data-tags")||"").split(",").map(e=>e.trim().toLowerCase()).filter(Boolean),o=s.includes(n);t.hidden=!o})}document.readyState==="loading"?document.addEventListener("DOMContentLoaded",initWritingTagFilter):initWritingTagFilter()